var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【부록-001】 관계자 증언</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS007M0000-01：<color=#ffd34c>【付録-001】関係者証言</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【Appendix-001】 Contact Testimony</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【附錄-001】 相關人士證言</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข FS007M0000-01: <color=#ffd34c>[เอกสารแนบท้าย-001] คำบอกเล่าจากคนรู้จัก</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số. FS007M0000-01: <color=#ffd34c>[Phụ Lục-001] Thẩm Vấn Mối Quan Hệ</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. FS007M0000-01: <color=#ffd34c>【附录-001】 相关人士证言</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. FS007M0000-01: <color=#ffd34c>【Anhang-001】 Kontakt-Zeugenaussage</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN\xA0FS007M0000-01\xA0: <color=#ffd34c>【Annexe-001】 Témoignage d'un contact</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"미나요?","JPN":"ミナですか？","ENG":"Mina?","TWN":"你說米娜？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그야 당연히 알죠. 우리 중학교에서 걔 모르는 애 없었을걸요.","JPN":"もちろん知ってます。うちの中学では、あの子を知らない人はいないと思います。","ENG":"Of course I know her. Everyone in my middle school probably knew about her.","TWN":"我當然認識她啊，我們中學幾乎沒有人不認識她的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"啊？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"혹시 동명이인 아니에요?","JPN":"ただの同姓同名とかじゃないんですか？","ENG":"Are we talking about the same person?","TWN":"不會是同名的兩個人吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"미나 걔는......","JPN":"ミナは……","ENG":"Mina was...","TWN":"米娜……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"말수가 적기는 해도 다른 사람 이야기를 잘 들어 주는 성격이었어요. ","JPN":"口数は少ないけど、人の話をちゃんと聞いてくれる子でした。","ENG":"She was a bit shy, but she was really a good listener. ","TWN":"她話雖然很少，但個性很擅長傾聽別人。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"왜, 그런 타입 있잖아요.","JPN":"ほら、そういうタイプいるじゃないですか。","ENG":"You know, the kind of person","TWN":"在我們身邊不也經常看到這種類型的朋友嗎。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"옆에 가만히 있는데 이런저런 이야기가 술술 나오는 타입.","JPN":"隣に黙っていてくれてるだけなのに、色んな話をしたくなる人。","ENG":"you can keep on talking to even if she's just sitting by your side.","TWN":"只是靜靜坐在你旁邊，你卻會自然地想跟她談天說地，她就是那種類型。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그리고....... 뭐랄까......","JPN":"それから……う～ん……","ENG":"And... she was...","TWN":"然後……怎麼說呢……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"역시 좀 얌전한 편이었어요. 미나 걔.","JPN":"ミナは、おとなしい方ではありましたね。","ENG":"She was definitely a modest girl. Mina, I mean.","TWN":"米娜應該算是比較文靜的女孩。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"중학생 때는 다들 왁자지껄하게 놀잖아요?","JPN":"中学の時って結構騒いだり、やんちゃしたりするじゃないですか？","ENG":"You know how typical teenagers are always loud and full of energy?","TWN":"國中的時候，大家都是吵吵鬧鬧的嘛。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 미나는 안 그랬어요.","JPN":"でもミナはそんな感じじゃありませんでした。","ENG":"But that wasn't the case for Mina.","TWN":"但米娜卻沒有那樣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다른 사람이 안 찾으면 혼자 조용히 앉아 있었거든요.","JPN":"誰かが話しかけないと、一人で黙って席に座ってるタイプ？","ENG":"She would always sit quietly unless someone talked to her first.","TWN":"沒人找她的時候，她都是一個人安靜地坐在位子上。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다른 애들보다 확실히 차분했어요.","JPN":"他の子より確かに静かではありましたね。","ENG":"She was certainly a lot calmer than the others.","TWN":"跟其他同學相比，她確實是比較穩重。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......제 기억으로는요.","JPN":"……あくまでも私の記憶ですが。","ENG":"At least in my memory.","TWN":"……在我的記憶中是這樣。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래서 오히려 남자애들에게 은근 인기 많았죠.","JPN":"あっ、男の子たちに結構人気ありましたよ。","ENG":"That's why Mina was quite popular amongst the boys.","TWN":"所以她在男生中的人氣很高。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};